import json
import psycopg2
import boto3
import logging
import os
import zipfile
import pandas as pd
from io import BytesIO
from utility.archive import archive
logger = logging.getLogger()
logger.setLevel(logging.INFO)
s3 = boto3.client("s3")
def unzip(filedata,conn,curr):
    filename=filedata[0]
    fil=filename.split(".")[0]
    filekey=filedata[4]
    bucketname=filedata[1]
    path=filekey.split("/")
    datetime=filedata[6].replace(" ","").replace(":","").replace("-","")
    pathbroke=''
    count=0
    for i in range(len(path)):
        if path[i]=='Land':
            count=i
            break
        pathbroke=f"{pathbroke}{path[i]}/"
    count+=1
    procpath=f"{pathbroke}Processed/"
    for i in range(count,len(path)-1):
        procpath=f"{procpath}{path[i]}/"
    procpath=f"{procpath}{fil}/{datetime}/"
    tmpdir='/tmp/zip'  
    os.makedirs(tmpdir,exist_ok=True)
    local_zip=os.path.join(tmpdir,filename)
    s3.download_file(bucketname, filekey, local_zip)
    with zipfile.ZipFile(local_zip,'r') as zip_ref:
        for member in zip_ref.infolist():
            if member.is_dir():
                continue
            print(member)
            file_name=member.filename.split("/")[-1]
            file_size=member.file_size
            filee=file_name.split('.')[0]
            print(file_name)
            file_type=file_name.split(".")[1]
            curr.execute("""select steps from public.intrn_kna_nitya_regex where filetype=%s and %s~regex order by filepriority limit 1;""",(file_type,file_name))
            actionsteps=curr.fetchall()
            print(actionsteps)
            steps = actionsteps[0]
            if len(actionsteps)>=1:
                print(f"step: {steps[0]}")
                if steps[0]=='copy':
                    file_name=member.filename
                    file_size=member.file_size
                    with zip_ref.open(member) as f:
                        s3.upload_fileobj(f, bucketname, f'{procpath}{filee}/{file_name}')
                        logger.info(f'File stored at: {procpath}{filee}/{file_name}')
                elif steps[0]=='flatten':
                    with zip_ref.open(member) as f:
                        filee=file_name.split('.')[0]
                        file_type=file_name.split(".")[1]
                        excel_data = f.read()
                        excelsheets=pd.ExcelFile(BytesIO(excel_data))
                        for sheet_name in excelsheets.sheet_names:
                            sheet=pd.read_excel(excelsheets,sheet_name=sheet_name)
                            exdata=BytesIO()
                            sheet.to_csv(exdata,index=False)
                            s3.put_object(Bucket=bucketname,Key=f"{procpath}{filee}/{sheet_name}.csv",Body=exdata.getvalue())
                            logger.info(f"Sheet {sheet_name} has been flattened to {procpath}")
                
    archive(filedata,conn,curr) 